mapper.select:
select 
from questions

  and deleted = false

    and bank_id = #{bankId}


    and (title like concat('%', #{keyword}, '%')
      or version_remark like concat('%', #{keyword}, '%')
      or chapter_name like concat('%', #{keyword}, '%'))


    and question_type = #{questionType}


    and status = #{status}


    and template_code = #{templateCode}


    and version_group_id like concat('%', #{versionGroupId}, '%')


order by question_id desc

